import { GoldRushClient } from "@covalenthq/client-sdk";

const client = new GoldRushClient(process.env.GOLDRUSH_API_KEY);

async function traceFundFlow(chainName, seedAddress, depth = 2) {
  const txns = await client.TransactionService.getTransactionsForAddressV3(
    chainName, seedAddress, { pageSize: 50 }
  );
  const hops = (txns.data?.items ?? []).map(tx => ({
    from: tx.from_address,
    to: tx.to_address,
    value: tx.value_quote,
  }));
  return { seedAddress, depth, hops };
}
